// Seeded PRNG (Mulberry32)
function createRng(seed) {
  let s = seed | 0;
  return function() {
    s = (s + 0x6d2b79f5) | 0;
    var t = Math.imul(s ^ (s >>> 15), 1 | s);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

// Fisher-Yates shuffle with provided RNG
function shuffle(arr, rng) {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(rng() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

// Generate perfect maze using recursive backtracker DFS
function generateMaze(rows, cols, rng) {
  const walls = [];
  for (let r = 0; r < rows; r++) {
    walls[r] = [];
    for (let c = 0; c < cols; c++) {
      walls[r][c] = { n: false, e: false, s: false, w: false };
    }
  }

  const visited = Array.from({length: rows}, () => Array(cols).fill(false));
  const stack = [{r: 0, c: 0}];
  visited[0][0] = true;

  while (stack.length > 0) {
    const current = stack[stack.length - 1];
    const neighbors = [];

    if (!visited[current.r][current.c - 1]) 
      neighbors.push({r: current.r, c: current.c - 1, dir: 'w'});
    if (!visited[current.r][current.c + 1]) 
      neighbors.push({r: current.r, c: current.c + 1, dir: 'e'});
    if (!visited[current.r - 1][current.c]) 
      neighbors.push({r: current.r - 1, c: current.c, dir: 'n'});
    if (!visited[current.r + 1][current.c]) 
      neighbors.push({r: current.r + 1, c: current.c, dir: 's'});

    if (neighbors.length > 0) {
      const next = neighbors[Math.floor(rng() * neighbors.length)];
      walls[current.r][current.c][next.dir] = true;
      switch(next.dir) {
        case 'n': walls[next.r][next.c].s = true; break;
        case 'e': walls[next.r][next.c].w = true; break;
        case 's': walls[next.r][next.c].n = true; break;
        case 'w': walls[next.r][next.c].e = true; break;
      }
      visited[next.r][next.c] = true;
      stack.push({r: next.r, c: next.c});
    } else {
      stack.pop();
    }
  }

  return walls;
}

